"use strict";(self.webpackChunktu_cis_4398_docs_template=self.webpackChunktu_cis_4398_docs_template||[]).push([["1148"],{3078:function(e){e.exports=JSON.parse('{"project":{"title":"BioGenie","description":"The Bioinformatics Chatbot is a cutting-edge web application designed to assist bioinformatics researchers with complex problems more efficiently. The application enables users to ask the chatbot questions and receive relevant, accurate answers. Using innovative learning technology and human-like behavior, the chatbot guides the researchers with step-by-step tutorials (answers) for complex bioinformatics questions. The methods provided to the chatbot will serve as the foundation for generating precise responses, enabling users to save time and focus on advancing their research. By harnessing the strength of AI, the web application is transforming how researchers tackle heartfelt problems leading to rapid advancements.\\n","documentation":"https://capstone-projects-2025-spring.github.io/project-003-bioinformatics-chatbot/","source":"https://github.com/Capstone-Projects-2025-Spring/project-003-bioinformatics-chatbot","tags":["bioinformatics","ai","llms","chatbot","research","python","javascript","shell","web","react","flask"],"demo":"https://www.youtube.com/watch?v=j1K0Ypl_iDk&t=5325","semester":"Spring 2025","slug":"biogenie","members":["Keith C Bunn","Amitai Goldmeer","Ishmam Kabir","Khanh Q Nguyen","Katerina Orlovskiy","Justin Truong","Troy K Witmer"]},"routeSlug":"biogenie-amitai-goldmeer","canonicalSlug":"biogenie"}')}}]);